commit fdc6090f1e018b8b519912b93c8cfb1b4e0d43fb
Author: David Addison <daddison@nvidia.com>
Date:   Mon Jun 8 08:47:15 2026 -0700

    Fix JSON finalization on early errors

    Early error returns can leave JSON objects or lists open when
    -J output is enabled.

    Close the remaining JSON containers during finalization and only
    append end_time when the writer is still at the root object.

    Reported-by: antgun42

    Signed-off-by: David Addison <daddison@nvidia.com>
---
 src/util.cu | 33 ++++++++++++++++++++++++++++-----
 1 file changed, 28 insertions(+), 5 deletions(-)

diff --git a/src/util.cu b/src/util.cu
index 5e22092..8e2b84d 100644
--- a/src/util.cu
+++ b/src/util.cu
@@ -232,6 +232,24 @@ static void jsonNull() {
   fprintf(json_report_fp, "null");
 }

+static void jsonFinishCurrent() {
+  switch(jsonCurrState()) {
+  case JSON_KEY:
+    jsonNull();
+    break;
+  case JSON_OBJECT_EMPTY:
+  case JSON_OBJECT_SOME:
+    jsonFinishObject();
+    break;
+  case JSON_LIST_EMPTY:
+  case JSON_LIST_SOME:
+    jsonFinishList();
+    break;
+  default:
+    assert(0);
+  }
+}
+
 // Write a (sanititzed) string
 static void jsonStr(const char *str) {
   if(str == nullptr) {
@@ -362,12 +380,17 @@ void jsonIdentifyWriter(bool is_writer) {
 void jsonOutputFinalize() {
   if(write_json) {

-    jsonKey("end_time");
-    char timebuffer[128];
-    formatNow(timebuffer, sizeof(timebuffer));
-    jsonStr(timebuffer);
+    if(state_n == 1 &&
+       (jsonCurrState() == JSON_OBJECT_EMPTY || jsonCurrState() == JSON_OBJECT_SOME)) {
+      jsonKey("end_time");
+      char timebuffer[128];
+      formatNow(timebuffer, sizeof(timebuffer));
+      jsonStr(timebuffer);
+    }

-    jsonFinishObject();
+    while(state_n > 0) {
+      jsonFinishCurrent();
+    }

     assert(jsonCurrState() == JSON_NONE);
     free(states);

