+  }
+
+  //collect baseline
+  timer tim;
+  for (int j=0; j<baseIter; j++) {
+      for (int i=0; i<args->nGpus; i++) {
+          CUDACHECK(cudaSetDevice(gpuids[i]));
+          copyOnStream((int*)ptrs[i], (int*)hostPtrs[i], nbytes, streams[i]);
